class Solution:
    def complexNumberMultiply(self, num1, num2):
        def parse(s):
            s = s[:-1]
            idx = s.index('+', 1)
            return int(s[:idx]), int(s[idx + 1:])
        a, b = parse(num1)
        c, d = parse(num2)
        real = a * c - b * d
        imag = a * d + b * c
        return str(real) + '+' + str(imag) + 'i'

