class Solution:
    def complexNumberMultiply(self, num1, num2):
        def parse(s):
            core = s[:-1]
            pos = core.index('+', 1)
            return int(core[:pos]), int(core[pos + 1:])
        a, b = parse(num1)
        c, d = parse(num2)
        return '%d+%di' % (a * c - b * d, a * d + b * c)

solutions.javascript:
var complexNumberMultiply = function(num1, num2) {
    const parse = (s) => {
        const core = s.slice(0, -1);
        const pos = core.indexOf('+', 1);
        return [parseInt(core.slice(0, pos), 10), parseInt(core.slice(pos + 1), 10)];
    };
    const [a, b] = parse(num1);
    const [c, d] = parse(num2);
    return (a * c - b * d) + '+' + (a * d + b * c) + 'i';
};
